#include <vector>
#include <queue>
#include <algorithm>
using namespace std;

long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    vector<pair<long long, long long>> a;
    for (int i = 0; i < n; ++i) {
        a.push_back({limit[i], value[i]});
    }
    sort(a.begin(), a.end());

    long long active_count = 0;
    priority_queue<long long, vector<long long>, greater<long long>> min_heap;

    for (int i = 0; i < n; ++i) {
        long long lim = a[i].first;
        long long val = a[i].second;
        if (active_count < lim) {
            min_heap.push(val);
            active_count++;
        }
        else if (!min_heap.empty() && min_heap.top() < val) {
            min_heap.pop();
            min_heap.push(val);
        }
    }

    long long ans = 0;
    while (!min_heap.empty()) {
        ans += min_heap.top();
        min_heap.pop();
    }
    return ans;
}
```

